#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static void controller_check_timeout(controller_t *controller, uint32_t now_ms)
{
    /* Check if either sensor has been stale for more than the timeout threshold */
    bool temp_stale = (controller->has_valid_temperature && 
                       (now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS));
    bool level_stale = (controller->has_valid_level && 
                        (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS));

    if (temp_stale || level_stale) {
        /* Go to safe all-off state */
        controller_set_safe_idle(controller);
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
    }
}

static void controller_update_state(controller_t *controller, int level, int temperature_c, bool has_valid_temp)
{
    /* Determine the state and actuator outputs based on current conditions */

    /* First check for timeout condition - if sensors are stale, go to safe idle */
    if (!has_valid_temperature || !has_valid_level) {
        controller_set_safe_idle(controller);
        return;
    }

    /* If level is below minimum heating threshold, heater must be OFF */
    bool heater_off_due_to_low_level = (level < CONTROLLER_MIN_HEATING_LEVEL);

    /* Determine the appropriate state and actuator outputs */
    if (level < 60) {
        /* FILLING: level too low, open inlet, keep heater off */
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (level > 75) {
        /* Level is high, close inlet. Heater depends on temperature and low-level guard */
        controller->inlet_open = false;

        /* If level < 55 at any time, keep heater OFF */
        if (heater_off_due_to_low_level) {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_IDLE;
        } else {
            /* Level is safe (>= 55), check temperature */
            if (temperature_c > 48) {
                /* Temp too high, turn off heater */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else if (temperature_c >= 47 && temperature_c <= 48) {
                /* Near upper band - check for rising temperature */
                bool temp_rising = (has_valid_temperature && 
