content.text:
#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->heater_was_on_when_entering_holding = false;
}

static void controller_check_timeout(controller_t *controller, uint32_t now_ms)
{
    /* Check if either sensor has been stale for more than the timeout threshold */
    bool temp_stale = (controller->has_valid_temperature && 
                       (now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS));
    bool level_stale = (controller->has_valid_level && 
                        (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS));

    if (temp_stale || level_stale) {
        /* Go to safe all-off state */
        controller_set_safe_idle(controller);
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
    }
}

static void controller_update_state(controller_t *controller, int level, int temperature_c, bool has_valid_temp)
{
    /* Determine the state and actuator outputs based on current conditions */

    /* First check for timeout condition - if sensors are stale, go to safe idle */
    if (!has_valid_temperature || !has_valid_level) {
        controller_set_safe_idle(controller);
        return;
    }

    /* If level is below minimum heating threshold, heater must be OFF */
    bool heater_off_due_to_low_level = (level < CONTROLLER_MIN_HEATING_LEVEL);

    /* Determine the appropriate state and actuator outputs */
    if (level < 60) {
        /* FILLING: level too low, open inlet, keep heater off */
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (level > 75) {
        /* Level is high, close inlet. Heater depends on temperature and low-level guard */
        controller->inlet_open = false;

        /* If level < 55 at any time, keep heater OFF */
        if (heater_off_due_to_low_level) {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_IDLE;
        } else {
            /* Level is safe (>= 55), check temperature */
            if (temperature_c > 48) {
                /* Temp too high, turn off heater */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else if (temperature_c >= 47 && temperature_c <= 48) {
                /* Near upper band - check for rising temperature */
                bool temp_rising = (has_valid_temperature && 
                                   controller->previous_temperature_c < temperature_c);
                if (temp_rising) {
                    /* Temperature is rising, turn off heater early */
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else {
                    /* Not rising, hold previous safe heater state */
                    controller->heater_on = controller->heater_was_on_when_entering_holding;
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            } else if (temperature_c >= 45) {
                /* 45 <= Temp < 47: hold previous safe heater state */
                controller->heater_on = controller->heater_was_on_when_entering_holding;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Temp < 45, turn on heater */
                controller->heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            }
        }
    } else {
        /* 60 <= level <= 75: check temperature */
        if (temperature_c > 48) {
            /* Temp too high, turn off heater */
            controller->inlet_open = false;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else if (temperature_c >= 47 && temperature_c <= 48) {
            /* Near upper band - check for rising temperature */
            bool temp_rising = (has_valid_temperature && 
                               controller->previous_temperature_c < temperature_c);
            if (temp_rising) {
                /* Temperature is rising, turn off heater early */
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Not rising, hold previous safe heater state */
                controller->inlet_open = false;
                controller->heater_on = controller->heater_was_on_when_entering_holding;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        } else if (temperature_c >= 45) {
            /* 45 <= Temp < 47: hold previous safe heater state */
            controller->inlet_open = false;
            controller->heater_on = controller->heater_was_on_when_entering_holding;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            /* Temp < 45, turn on heater */
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        }
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for timeout condition first - this forces safe idle */
    bool timed_out = false;
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        timed_out = true;
    }

    /* Update sensor validity and values based on input */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    default:
        /* For other inputs (NONE, timeout, invalid), don't update sensor values */
        break;
    }

    /* Check if we have valid data from both sensors */
    bool has_valid_temp = controller->has_valid_temperature;
    bool has_valid_level = controller->has_valid_level;

    /* If this was a timeout/invalid input, reset validity flags */
    if (timed_out) {
        controller_set_safe_idle(controller);
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        timed_out = true;  /* Mark as timed out for output */
    }

    /* Check timeout condition based on time since last valid sensor reading */
    if (!timed_out) {
        controller_check_timeout(controller, input.now_ms);
    }

    /* If we're in safe idle due to timeout, ensure actuators are off */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
        controller->inlet_open = false;
        controller->heater_on = false;
        timed_out = true;  /* Mark as timed out for output */
    }

    /* If we have valid data from both sensors, apply control policy */
    if (!timed_out && has_valid_temp && has_valid_level) {
        controller_update_state(controller, controller->last_level, 
                                controller->last_temperature_c, has_valid_temp);

        /* Track heater state only when transitioning INTO HOLDING from another state */
        bool previous_holding = (previous_state == CONTROLLER_STATE_HOLDING);
        if (!previous_holding && controller->state == CONTROLLER_STATE_HOLDING) {
            /* We just entered HOLDING, save the current heater state */
            controller->heater_was_on_when_entering_holding = controller->heater_on;
        }
    } else {
        /* Not enough valid data - stay in safe idle with actuators off */
        controller_set_safe_idle(controller);
        timed_out = true;  /* Mark as timed out for output (not having both sensors) */
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    output.timed_out = timed_out;

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_FILL_LEVEL_THRESHOLD 60
#define CONTROLLER_MIN_HEATING_LEVEL 55
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 75
#define CONTROLLER_TEMP_LOW_THRESHOLD 45
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 48
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILLING,
    CONTROLLER_STATE_HEATING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    bool has_valid_temperature;
    int previous_temperature_c;
    int last_temperature_c;
    uint32_t last_temperature_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
    /* Track heater state when entering HOLDING for 47-48 temp band */
    bool heater_was_on_when_entering_holding;
} controller_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

